  onCommandChange: () => void;
  /**
   * Move the highlight by `direction` rows (+1 = down, -1 = up).
   * Wraps around at both ends: ArrowDown on last item → index 0;
   * ArrowUp on index 0 → last item; ArrowUp from -1 → last item (DP-2: A).
   */
